nt-smoothing:auto !important;line-height:19.2px !important}\n.et_pb_section .pts-prf-stat{-webkit-font-smoothing:auto !important}\n.et_pb_section .pts-prf-stats-bar{margin-bottom:40px !important}\n\n@media(max-width:768px){\n  .pts-prf-stats-bar{grid-template-columns:repeat(2,1fr);gap:24px}\n  .pts-prf-stat:not(:last-child){border-right:none}\n  .pts-prf-stat:nth-child(odd){border-right:1px solid rgba(255,255,255,0.1)}\n  .pts-prf-title{font-size:28px}\n  .pts-prf-stat-value{font-size:32px}\n}\n@media(max-width:480px){\n  .pts-prf-stats-bar{grid-template-columns:1fr}\n  .pts-prf-stat:nth-child(odd){border-right:none}\n}\n@media(prefers-reduced-motion:reduce){.pts-prf-section *{transition:none !important}}\n/* === THAI FONT OVERRIDE (pts-prf) === */\n.pts-prf-label, .pts-prf-title, .pts-prf-text,\n.pts-prf-stat-value, .pts-prf-stat-label {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n}\n\n/* === LOGISTICS === */\n.pts-log-section{background:#F5F7FA;padding:80px 24px;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.pts-log-inner{max-width:900px;margin:0 auto}\n.pts-log-label{display:block;text-align:center;font-family:\'JetBrains Mono\',monospace;font-size:12px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;color:#0369a1;margin-bottom:16px}\n.pts-log-title{font-family:\'Noto Sans\',sans-serif;font-size:36px;font-weight:700;color:#000864;text-align:center;line-height:1.25;margin:0 0 16px;padding:0}\n.pts-log-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:20px}\n.pts-log-item{display:flex;gap:16px;align-items:flex-start;background:#fff;border-radius:12px;padding:20px}\n.pts-log-icon{width:40px;height:40px;border-radius:8px;background:rgba(3,105,161,0.1);display:flex;align-items:center;justify-content:center;flex-shrink:0}\n.pts-log-icon svg{stroke:#0369a1}\n.pts-log-item-label{font-family:\'Noto Sans\',sans-serif;font-size:14px;font-weight:600;color:#000864;margin-bottom:2px}\n.pts-log-item-value{font-family:\'Noto Sans\',sans-serif;font-size:15px;font-weight:400;color:#333;line-height:1.5}\n\n.et_pb_section .pts-log-title{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .pts-log-label{-webkit-font-smoothing:auto !important;line-height:19.2px !important}\n.et_pb_section .pts-log-item-label,.et_pb_section .pts-log-item-value{-webkit-font-smoothing:auto !important}\n\n@media(max-width:768px){\n  .pts-log-grid{grid-template-columns:1fr}\n  .pts-log-title{font-size:28px}\n}\n@media(prefers-reduced-motion:reduce){.pts-log-section *{transition:none !important}}\n/* === THAI FONT OVERRIDE (pts-log) === */\n.pts-log-label, .pts-log-title,\n.pts-log-item-label, .pts-log-item-value {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n}\n\n/* === REGISTRATION CTA === */\n.pts-reg-section{background:linear-gradient(165deg,#0f1419 0%,#1a2632 40%,#000864 100%);padding:80px 24px;text-align:center;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.pts-reg-section::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg viewBox=\'0 0 400 400\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cfilter id=\'n\'%3E%3CfeTurbulence type=\'fractalNoise\' baseFrequency=\'0.9\' numOctaves=\'4\' stitchTiles=\'stitch\'/%3E%3C/filter%3E%3Crect width=\'100%25\' height=\'100%25\' filter=\'url(%23n)\'/%3E%3C/svg%3E");opacity:0.03;pointer-events:none;z-index:1}\n.pts-reg-section>*{position:relative;z-index:2}\n.pts-reg-section h2{font-family:\'Noto Sans\',sans-serif;font-size:40px;font-weight:700;color:#fff;margin:0 0 16px;padding:0}\n.pts-reg-meta{font-family:\'Noto Sans\',sans-serif;font-size:18px;color:rgba(255,255,255,0.85);margin:0 0 32px;padding:0}\n.pts-reg-cta{display:inline-flex;align-items:center;gap:8px;font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#fff;background:#0369a1;padding:20px 48px;border-radius:12px;text-decoration:none;transition:all 0.3s ease;box-shadow:0 4px 20px rgba(3,105,161,0.4)}\n.pts-reg-cta:hover{background:rgb(53,135,180);transform:translateY(-2px);box-shadow:0 8px 24px rgba(3,105,161,0.3)}\n.pts-reg-secondary{font-family:\'Noto Sans\',sans-serif;font-size:14px;color:rgba(255,255,255,0.85);margin-top:24px;padding:0}\n.pts-reg-secondary a{color:#fff;text-decoration:underline;transition:color 0.3s ease}\n.pts-reg-secondary a:hover{color:#fff}\n\n.et_pb_section .pts-reg-section h2{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .pts-reg-cta{-webkit-font-smoothing:auto !important;line-height:28.8px !important}\n.et_pb_section .pts-reg-meta,.et_pb_section .pts-reg-secondary{-webkit-font-smoothing:auto !important;padding-bottom:0 !important}\n\n@media(max-width:768px){\n  .pts-reg-section h2{font-size:32px}\n  .pts-reg-cta{width:100%;justify-content:center;padding:16px 32px;font-size:16px}\n}\n@media(prefers-reduced-motion:reduce){.pts-reg-section *{transition:none !important}}\n/* === THAI FONT OVERRIDE (pts-reg) === */\n.pts-reg-title, .pts-reg-meta,\n.pts-reg-btn--primary, .pts-reg-secondary, .pts-reg-secondary-link {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n}\n\n/* === RELATED EVENTS === */\n.pts-rel-section{background:#F5F7FA;padding:80px 24px;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.pts-rel-inner{max-width:1100px;margin:0 auto}\n.pts-rel-label{display:block;text-align:center;font-family:\'JetBrains Mono\',monospace;font-size:12px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;color:#0369a1;margin-bottom:16px}\n.pts-rel-title{font-family:\'Noto Sans\',sans-serif;font-size:36px;font-weight:700;color:#000864;text-align:center;line-height:1.25;margin:0 0 16px;padding:0}\n.pts-rel-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:24px}\n.pts-rel-card{background:#fff;border-radius:16px;overflow:hidden;transition:transform 0.3s ease,box-shadow 0.3s ease}\n.pts-rel-card:hover{transform:translateY(-4px);box-shadow:0 12px 40px rgba(0,0,0,0.08)}\n.pts-rel-card-border{height:4px}\n.pts-rel-card-body{padding:28px}\n.pts-rel-badge{display:inline-block;font-family:\'JetBrains Mono\',monospace;font-size:11px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;padding:4px 12px;border-radius:50px;margin-bottom:12px}\n.pts-rel-card h3{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#000864;line-height:1.4;margin:0 0 16px;padding:0}\n.pts-rel-meta{display:flex;flex-direction:column;gap:8px;margin-bottom:16px}\n.pts-rel-meta-item{display:flex;align-items:center;gap:6px;font-family:\'Noto Sans\',sans-serif;font-size:14px;color:#5b6b80}\n.pts-rel-meta-item svg{flex-shrink:0;stroke:#94a3b8}\n.pts-rel-link{display:inline-flex;align-items:center;gap:4px;font-family:\'Noto Sans\',sans-serif;font-size:14px;font-weight:600;text-decoration:none;transition:opacity 0.3s ease}\n.pts-rel-link:hover{opacity:0.8}\n\n.et_pb_section .pts-rel-title{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .pts-rel-label{-webkit-font-smoothing:auto !important;line-height:19.2px !important}\n.et_pb_section .pts-rel-card h3{-webkit-font-smoothing:auto !important;margin:0 0 16px !important;padding:0 !important}\n\n@media(max-width:768px){\n  .pts-rel-grid{grid-template-columns:1fr}\n  .pts-rel-title{font-size:28px}\n}\n@media(prefers-reduced-motion:reduce){.pts-rel-card{transition:none !important}}\n/* === THAI FONT OVERRIDE (pts-rel) === */\n.pts-rel-label, .pts-rel-title,\n.pts-rel-card-badge, .pts-rel-card-date, .pts-rel-card-location {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n}\n\n\n/* === THAI TYPOGRAPHY === */\n/* Font loaded via <link> in header — do NOT use @import here (invalid after rules) */\n\n/* Thai font stack for all body text */\nbody, .et_pb_section, .et_pb_code, .et_pb_code_inner {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n}\n\n/* Thai-specific line heights (Thai script is taller — needs !important to override Divi) */\np, li, .et_pb_text_inner { line-height: 1.8 !important; }\nh1, h2, h3, h4, h5, h6 { line-height: 1.4 !important; }\n\n/* Thai label override: JetBrains Mono doesn\'t have Thai glyphs.\n   letter-spacing breaks Thai script (chars within words must stay connected).\n   text-transform:uppercase is meaningless for Thai. */\n[class*="-label"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n/* Also fix any monospace elements that might contain Thai text */\n[class*="-source"], [class*="-company"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}</style><!-- /wp:html -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Event Hero"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Event Hero: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Event Hero: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="pts-hero-section">\n  <div class="pts-hero-superd" aria-hidden="true"></div>\n  <a href="/th/news/" class="pts-hero-back">\n    <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="16" height="16"><path d="M19 12H5M12 19l-7-7 7-7"/></svg>\n    กลับไปข่าวสารและกิจกรรม\n  </a>\n  <span class="pts-hero-badge">สัมมนา</span>\n  <h1>Production Transparency: จากรายงานกระดาษสู่แดชบอร์ดเรียลไทม์</h1>\n  <p class="pts-hero-subtitle">ค้นพบวิธีที่โรงงานเปลี่ยนจากการรายงานผลผลิตด้วยกระดาษ สู่แดชบอร์ดการผลิตแบบเรียลไทม์ ที่แจ้งปัญหาก่อนจะกลายเป็นความล่าช้าที่มีต้นทุนสูง</p>\n\n  <div class="pts-hero-facts">\n    \n      <div class="pts-hero-fact">\n        <div class="pts-hero-fact-icon">\n          <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="18" height="18"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>\n        </div>\n        <div class="pts-hero-fact-value">10 เมษายน 2569</div>\n        <div class="pts-hero-fact-label">วันพฤหัสบดี</div>\n      </div>\n\n      <div class="pts-hero-fact">\n        <div class="pts-hero-fact-icon">\n          <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="18" height="18"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>\n        </div>\n        <div class="pts-hero-fact-value">13:00 – 17:00</div>\n        <div class="pts-hero-fact-label">ครึ่งวัน</div>\n      </div>\n\n      <div class="pts-hero-fact">\n        <div class="pts-hero-fact-icon">\n          <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="18" height="18"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z"/><circle cx="12" cy="10" r="3"/></svg>\n        </div>\n        <div class="pts-hero-fact-value">กรุงเทพฯ</div>\n        <div class="pts-hero-fact-label">ประเทศไทย</div>\n      </div>\n\n      <div class="pts-hero-fact">\n        <div class="pts-hero-fact-icon">\n          <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="18" height="18"><path d="M17 21v-2a4 4 0 00-4-4H5a4 4 0 00-4-4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 00-3-3.87"/><path d="M16 3.13a4 4 0 010 7.75"/></svg>\n        </div>\n        <div class="pts-hero-fact-value">50 ที่นั่ง</div>\n        <div class="pts-hero-fact-label">จำกัดจำนวน</div>\n      </div>\n  </div>\n\n  <a href="#register" class="pts-hero-cta">\n    ลงทะเบียนสำรองที่นั่ง\n    <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="16" height="16"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>\n  </a>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"The Problem"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"The Problem: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"The Problem: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="pts-prob-section">\n  <div class="pts-prob-inner">\n    <span class="pts-prob-label">ความท้าทาย</span>\n    <h2 class="pts-prob-title">ข้อมูลจากพื้นที่การผลิตของคุณช้ากว่าความเป็นจริงหนึ่งวัน</h2>\n  </div>\n  <div class="pts-prob-body">\n    \n    <p>โรงงานผลิตไทยส่วนใหญ่ยังคงพึ่งพารายงานกระดาษที่กรอกตอนสิ้นกะ พนักงานจดยอดการผลิต บันทึกปัญหาคุณภาพด้วยลายมือ แล้วส่งคลิปบอร์ดให้หัวหน้างานคีย์ตัวเลขลงสเปรดชีตในเช้าวันรุ่งขึ้น กว่าผู้บริหารจะเห็นข้อมูล มันก็เป็นข่าวเมื่อวานไปแล้ว</p>\n\n    <p>ต้นทุนที่แท้จริงไม่ใช่แค่ความล่าช้า — แต่เป็นการตัดสินใจโดยไม่มีข้อมูลปัจจุบัน ผู้จัดการจัดสรรทรัพยากรจากตัวเลขที่ไม่ตรงกับสถานการณ์จริงอีกต่อไป ปัญหาคุณภาพที่สามารถจับได้ในไม่กี่นาทีกลับถูกมองข้ามเป็นชั่วโมง เปลี่ยนจากข้อบกพร่องเล็กน้อยเป็นของเสียทั้งล็อต เครื่องจักรที่ทำงานต่ำกว่าประสิทธิภาพไม่ได้รับการแก้ไขจนกว่ารายงานวันรุ่งขึ้นจะถึงมือ</p>\n\n    <p>ความแตกต่างระหว่างการจับปัญหาแบบเรียลไทม์กับการค้นพบล่าช้าหนึ่งวัน อาจต่างกันถึง <strong>10 เท่าในแง่ต้นทุน</strong> แดชบอร์ด MES (ระบบบริหารการผลิต) เปลี่ยนสมการนี้ทั้งหมด — ให้คุณเห็นภาพการผลิตแบบเรียลไทม์ เพื่อตัดสินใจจากสิ่งที่เกิดขึ้นตอนนี้ ไม่ใช่เมื่อวาน</p>\n    \n    <div class="pts-prob-data-card">\n      <div class="pts-prob-data-content">\n        <div class="pts-prob-data-number">รายงานกระดาษ</div>\n        <div class="pts-prob-data-arrow">&darr;</div>\n        <div class="pts-prob-data-number pts-prob-data-number--success">แดชบอร์ดเรียลไทม์</div>\n        <div class="pts-prob-data-label">จับปัญหาในนาที ไม่ใช่เป็นวัน</div>\n      </div>\n    </div>\n    \n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Outcomes"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Outcomes: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Outcomes: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="pts-out-section">\n  <div class="pts-out-inner">\n    <span class="pts-out-label">สิ่งที่จะได้รับ</span>\n    <h2 class="pts-out-title">สิ่งที่คุณจะนำกลับไปจากสัมมนา</h2>\n    <div class="pts-out-grid">\n      \n    <div class="pts-out-card">\n      <div class="pts-out-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="24" height="24"><line x1="12" y1="1" x2="12" y2="23"/><path d="M17 5H9.5a3.5 3.5 0 000 7h5a3.5 3.5 0 010 7H6"/></svg>\n      </div>\n      <h3>เข้าใจต้นทุนของการเห็นข้อมูลการผลิตล่าช้า</h3>\n      <p>วัดผลว่าข้อมูลที่ช้าจริง ๆ แล้วทำให้โรงงานสูญเสียเท่าไร — ทั้งของเสีย งานแก้ไข การส่งมอบที่พลาด และค่าล่วงเวลา</p>\n    </div>\n\n    <div class="pts-out-card">\n      <div class="pts-out-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="24" height="24"><rect x="2" y="3" width="20" height="14" rx="2" ry="2"/><line x1="8" y1="21" x2="16" y2="21"/><line x1="12" y1="17" x2="12" y2="21"/></svg>\n      </div>\n      <h3>เห็นแดชบอร์ด MES ทำงานจริงกับข้อมูลจากโรงงานไทย</h3>\n      <p>ไม่ใช่สไลด์หรือแบบจำลอง — แดชบอร์ด MES ที่ทำงานจริง พร้อมข้อมูลการผลิตจริงจากโรงงานไทย</p>\n    </div>\n\n    <div class="pts-out-card">\n      <div class="pts-out-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="24" height="24"><polyline points="22 12 18 12 15 21 9 3 6 12 2 12"/></svg>\n      </div>\n      <h3>ระบุตัวชี้วัดการผลิตที่สำคัญที่สุดสำหรับอุตสาหกรรมของคุณ</h3>\n      <p>OEE (ประสิทธิผลโดยรวมของเครื่องจักร), อัตราผลผลิต, Cycle Time, First-Pass Quality — เรียนรู้ว่าควรติดตาม KPI ใดก่อน ตามประเภทการผลิตของคุณ</p>\n    </div>\n\n    <div class="pts-out-card">\n      <div class="pts-out-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="24" height="24"><rect x="4" y="2" width="16" height="20" rx="2"/><line x1="8" y1="6" x2="16" y2="6"/><line x1="8" y1="10" x2="16" y2="10"/><line x1="8" y1="14" x2="12" y2="14"/></svg>\n      </div>\n      <h3>สร้าง Business Case สำหรับการเปลี่ยนพื้นที่การผลิตสู่ดิจิทัลแบบเรียลไทม์</h3>\n      <p>กลับไปพร้อมกรอบการนำเสนอ ROI ของ MES ให้ทีมผู้บริหาร — อิงจากตัวเลขจริง ไม่ใช่คำสัญญาจากผู้ขาย</p>\n    </div>\n    </div>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Agenda"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Agenda: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Agenda: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="pts-agd-section">\n  <div class="pts-agd-inner">\n    <span class="pts-agd-label">กำหนดการครึ่งวัน</span>\n    <h2 class="pts-agd-title">บ่ายที่จัดเต็ม — ไม่ใช่การขายสินค้า</h2>\n    <p class="pts-agd-subtitle">ทุกช่วงออกแบบมาเพื่อสิ่งที่คุณจะนำกลับไปใช้ — ไม่ใช่สิ่งที่เราจะขาย</p>\n  </div>\n  <div class="pts-agd-timeline">\n    \n    <div class="pts-agd-item">\n      <div class="pts-agd-time">13:00 – 13:15</div>\n      <div class="pts-agd-content">\n        <h3>ลงทะเบียนและพบปะ</h3>\n        <p>กาแฟ แนะนำตัว และสำรวจกระบวนการรายงานการผลิตปัจจุบันของคุณ</p>\n      </div>\n    </div>\n\n    <div class="pts-agd-item">\n      <div class="pts-agd-time">13:15 – 14:00</div>\n      <div class="pts-agd-content">\n        <h3>ทำไมรายงานกระดาษมีต้นทุนมากกว่าที่คิด</h3>\n        <p>ต้นทุนแฝงของข้อมูลการผลิตที่ล่าช้า — ทั้งของเสีย งานแก้ไข ค่าล่วงเวลา และการส่งมอบที่พลาด ตัวอย่างจริงจากโรงงานไทย</p>\n      </div>\n    </div>\n\n    <div class="pts-agd-item">\n      <div class="pts-agd-time">14:00 – 14:45</div>\n      <div class="pts-agd-content">\n        <h3>สาธิตแบบเรียลไทม์ — เดินชมแดชบอร์ด MES</h3>\n        <p>แดชบอร์ด MES ที่ทำงานจริงกับข้อมูลจากโรงงานจริง ดูสถานะการผลิต การแจ้งเตือนคุณภาพ และการติดตาม OEE แบบเรียลไทม์ — ไม่ใช่สไลด์</p>\n      </div>\n    </div>\n\n    <div class="pts-agd-item pts-agd-item--break">\n      <div class="pts-agd-time">14:45 – 15:00</div>\n      <div class="pts-agd-content">\n        <h3>พักรับประทานกาแฟ</h3>\n        \n      </div>\n    </div>\n\n    <div class="pts-agd-item">\n      <div class="pts-agd-time">15:00 – 15:45</div>\n      <div class="pts-agd-content">\n        <h3>เลือก KPI ที่เหมาะกับโรงงานของคุณ</h3>\n        <p>ไม่ใช่ทุกตัวชี้วัดที่สำคัญเท่ากัน เรียนรู้วิธีเลือก KPI การผลิตที่ขับเคลื่อนการปรับปรุงจริงสำหรับประเภทการผลิตของคุณ</p>\n      </div>\n    </div>\n\n    <div class="pts-agd-item">\n      <div class="pts-agd-time">15:45 – 16:30</div>\n      <div class="pts-agd-content">\n        <h3>เสวนา: ประสบการณ์จริงจากโรงงานที่ใช้ MES</h3>\n        <p>ฟังจากผู้ปฏิบัติงานในโรงงานที่เปลี่ยนจากกระดาษสู่ดิจิทัล — อะไรได้ผล อะไรที่ไม่คาดคิด และอะไรที่อยากทำต่างไป</p>\n      </div>\n    </div>\n\n    <div class="pts-agd-item">\n      <div class="pts-agd-time">16:30 – 17:00</div>\n      <div class="pts-agd-content">\n        <h3>ถาม-ตอบ + ขั้นตอนต่อไป</h3>\n        <p>เปิดเวทีสนทนา คำถามเฉพาะเจาะจงเกี่ยวกับสถานการณ์ของโรงงานคุณ และคำแนะนำว่าควรเริ่มจากตรงไหน</p>\n      </div>\n    </div>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Who Should Attend"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Who Should Attend: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Who Should Attend: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="pts-per-section">\n  <div class="pts-per-inner">\n    <span class="pts-per-label">เหมาะกับใคร</span>\n    <h2 class="pts-per-title">สัมมนานี้เหมาะกับคุณหรือไม่?</h2>\n    <div class="pts-per-grid">\n      \n    <div class="pts-per-card">\n      <div class="pts-per-accent"></div>\n      <div class="pts-per-body">\n        <div class="pts-per-role">เจ้าของโรงงาน / ผู้จัดการโรงงาน</div>\n        <span class="pts-per-size">โรงงานผลิตทุกขนาด</span>\n        <p class="pts-per-desc">คุณรับผิดชอบผลการดำเนินงานโรงงานโดยรวม แต่ต้องพึ่งพารายงานสิ้นวันเพื่อเข้าใจว่าเกิดอะไรขึ้นในสายการผลิต คุณต้องการเห็นภาพรวมโดยไม่ต้องเดินไปถามเอง</p>\n        <p class="pts-per-quote">"ผมต้องรู้ว่าเกิดอะไรขึ้นบนสายการผลิต โดยไม่ต้องเดินไปถามเอง"</p>\n      </div>\n    </div>\n\n    <div class="pts-per-card">\n      <div class="pts-per-accent"></div>\n      <div class="pts-per-body">\n        <div class="pts-per-role">ผู้จัดการฝ่ายผลิต / ฝ่ายปฏิบัติการ</div>\n        <span class="pts-per-size">พนักงาน 50-500 คน</span>\n        <p class="pts-per-desc">คุณจัดการตารางการผลิตรายวันและแก้ปัญหาเฉพาะหน้า — แต่คุณแก้ได้เฉพาะสิ่งที่มองเห็น แบบฟอร์มกระดาษให้ภาพของเมื่อวาน ไม่ใช่ความจริงของวันนี้</p>\n        <p class="pts-per-quote">"ผมต้องการข้อมูลที่ไว้ใจได้ ไม่ใช่ตัวเลขจากกระดาษของเมื่อวาน"</p>\n      </div>\n    </div>\n    </div>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Proof & Social Signal"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Proof & Social Signal: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Proof & Social Signal: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="pts-prf-section">\n  <div class="pts-prf-inner">\n    <span class="pts-prf-label">ทำไมต้องกิจกรรม DigiWin</span>\n    <h2 class="pts-prf-title">เรียนรู้จากทีมที่ทำมาแล้วกว่า 100+ ครั้ง</h2>\n    <div class="pts-prf-stats-bar">\n      \n    <div class="pts-prf-stat">\n      <div class="pts-prf-stat-value">100+</div>\n      <div class="pts-prf-stat-label">การติดตั้งในไทย</div>\n    </div>\n\n    <div class="pts-prf-stat">\n      <div class="pts-prf-stat-value">44</div>\n      <div class="pts-prf-stat-label">ปีเชี่ยวชาญด้านการผลิต</div>\n    </div>\n\n    <div class="pts-prf-stat">\n      <div class="pts-prf-stat-value">95%</div>\n      <div class="pts-prf-stat-label">อัตราต่อสัญญา</div>\n    </div>\n\n    <div class="pts-prf-stat">\n      <div class="pts-prf-stat-value">50+</div>\n      <div class="pts-prf-stat-label">ทีมงานคนไทย</div>\n    </div>\n    </div>\n    <p class="pts-prf-text">DigiWin ช่วยผู้ผลิตไทยเปลี่ยนพื้นที่การผลิตสู่ดิจิทัลมากว่า 8 ปี สัมมนานี้ย่อประสบการณ์ทั้งหมดไว้ในบ่ายเดียว — กรอบงาน Production Transparency เดียวกับที่ทีมติดตั้งใช้กับลูกค้า MES ทุกราย</p>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Logistics"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","righ