"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Related Events: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Related Events: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="pts-rel-section">\n  <div class="pts-rel-inner">\n    <span class="pts-rel-label">กิจกรรมอื่นที่กำลังจะมาถึง</span>\n    <h2 class="pts-rel-title">เรียนรู้ต่อเนื่อง</h2>\n    <div class="pts-rel-grid">\n      \n    <div class="pts-rel-card">\n      <div class="pts-rel-card-border" style="background:#15803d"></div>\n      <div class="pts-rel-card-body">\n        <span class="pts-rel-badge" style="color:#15803d;background:rgba(21,128,61,0.12)">เวิร์กช็อป</span>\n        <h3>BOI Compliance Workshop: Production-Level Reconciliation That Passes Every Audit</h3>\n        <div class="pts-rel-meta">\n          <div class="pts-rel-meta-item">\n            <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>\n            March 15, 2026\n          </div>\n          <div class="pts-rel-meta-item">\n            <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z"/><circle cx="12" cy="10" r="3"/></svg>\n            Bangkok, Thailand\n          </div>\n        </div>\n        <a href="/th/news/events/boi-compliance-workshop/" class="pts-rel-link" style="color:#15803d">Learn More\n          <svg aria-hidden="true" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>\n        </a>\n      </div>\n    </div>\n\n    <div class="pts-rel-card">\n      <div class="pts-rel-card-border" style="background:#b45309"></div>\n      <div class="pts-rel-card-body">\n        <span class="pts-rel-badge" style="color:#b45309;background:rgba(180,83,9,0.12)">เยี่ยมชมโรงงาน</span>\n        <h3>Live Factory Tour: See DigiWin MES in Action</h3>\n        <div class="pts-rel-meta">\n          <div class="pts-rel-meta-item">\n            <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>\n            May 8, 2026\n          </div>\n          <div class="pts-rel-meta-item">\n            <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z"/><circle cx="12" cy="10" r="3"/></svg>\n            EEC Industrial Zone\n          </div>\n        </div>\n        <a href="/th/news/events/factory-tour-mes/" class="pts-rel-link" style="color:#b45309">Learn More\n          <svg aria-hidden="true" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>\n        </a>\n      </div>\n    </div>\n\n    <div class="pts-rel-card">\n      <div class="pts-rel-card-border" style="background:#6d28d9"></div>\n      <div class="pts-rel-card-body">\n        <span class="pts-rel-badge" style="color:#6d28d9;background:rgba(109,40,217,0.12)">งานแสดงสินค้า</span>\n        <h3>Manufacturing Expo 2026: DigiWin Thailand Booth</h3>\n        <div class="pts-rel-meta">\n          <div class="pts-rel-meta-item">\n            <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>\n            May 20–22, 2026\n          </div>\n          <div class="pts-rel-meta-item">\n            <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z"/><circle cx="12" cy="10" r="3"/></svg>\n            BITEC, Bangkok\n          </div>\n        </div>\n        <a href="/th/news/events/manufacturing-expo-2026/" class="pts-rel-link" style="color:#6d28d9">Learn More\n          <svg aria-hidden="true" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>\n        </a>\n      </div>\n    </div>\n    </div>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
